return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'et','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Palun värskendage pistikprogramm TranslatePress - Multilingual versioonile %1$s või kõrgemale, et %2$s töötaks õigesti.','Please install and activate the TranslatePress - Multilingual plugin'=>'Palun paigaldage ja aktiveerige pistikprogramm TranslatePress - Multilingual','Install & Activate'=>'Paigalda ja aktiveeri','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Palun värskendage TranslatePress - Multilingual versioonile %2$s või uuemale. Teie praegu paigaldatud TranslatePress - Multilingual versioon ei ühildu enam %1$s praeguse versiooniga.','All TranslatePress functionalities are disabled until then.'=>'Kõik TranslatePress funktsioonid on seni keelatud.','Update Now'=>'Uuenda kohe','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'See TranslatePress lisa on üle viidud põhipistikprogrammi ja seda enam ei kasutata. Saate selle kustutada.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> nõuab töötamiseks vähemalt PHP versiooni 5.6.20+. See on <a href="%s">viimase WordPressi versiooni miinimumnõue</a>. Palun võtke ühendust oma serveri administraatoriga, et uuendada oma PHP versiooni.','Advanced'=>'Täpsemad','Settings saved.'=>'Seaded on salvestatud.','Are you sure you want to remove this item?'=>'Kas olete kindel, et soovite selle üksuse eemaldada?','Remove'=>'Eemalda','Add'=>'Lisa','Select...'=>'Vali...','[%s] Low TranslatePress AI Words'=>'[%s] TranslatePress AI sõnad on lõppemas','upgrade your plan or get extra AI Words'=>'uuendage oma paketti või hankige täiendavaid AI sõnu','upgrade your plan'=>'uuendage oma paketti','TranslatePress AI words are running low on your site.'=>'Teie saidil hakkavad TranslatePress AI sõnad otsa saama.','Current status: %s words remaining'=>'Praegune seis: %s sõna jäänud','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Kui järelejäänud AI sõnad otsa saavad, peatatakse automaatne tõlkimine TranslatePress AI kaudu.','To continue translating your content, please %1$s over at %2$s'=>'Sisu tõlkimise jätkamiseks palun %1$s saidil %2$s','Manage Notification: %s'=>'Halda teavitust: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Saadaval on %1$s uus versioon. %2$sVaata versiooni %3$s üksikasju%4$s või %5$suuenda kohe%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Saadaval on %1$s uus versioon. %2$sVaata versiooni %3$s üksikasju%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Uuenduste lubamiseks palun %1$ssisesta oma litsentsivõti%2$s. Vajad litsentsivõtit? %3$sOsta nüüd%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Uuenduste lubamiseks palun mine %1$slitsentsi lehele%2$s ja kontrolli, et sul oleks kehtiv litsents.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Uuenduste lubamiseks tuleb sinu litsents uuendada. Palun mine %1$sTranslatePress Account%2$s lehele ja logi sisse, et uuendada.','You do not have permission to install plugin updates'=>'Sul pole õigust paigaldada pistikprogrammi uuendusi','Error'=>'Viga','Your TranslatePress license key is invalid or missing.'=>'Sinu TranslatePress litsentsivõti on kehtetu või puudub.','Your license key expired on %s.'=>'Sinu litsentsivõti aegus %s.','Your license key has been disabled.'=>'Sinu litsentsivõti on keelatud.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Sinu litsentsivõti on selle URL-i jaoks keelatud. Taasaktiveeri see lehelt <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Halda saite.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Litsentsivõtme vastuolu.</strong> Sisestatud litsents ei ühti sinu paigaldatud TranslatePress versiooniga.</p><p>Palun kontrolli, et oled oma TranslatePress kontolt paigaldanud õige versiooni oma litsentsi jaoks.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Kui sul on paigaldatud ainult tasuta pistikprogramm, kuid oled lisanud tasulise litsentsi, palun paigalda tasuline pistikprogramm oma TranslatePress kontolt.','Your license key has reached its activation limit.'=>'Sinu litsentsivõti on jõudnud aktiveerimise limiidini.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Täienda oma paketti rohkemate saitide lisamiseks. %1$sTäienda nüüd%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'See veebisait on juba aktiveeritud tasuta litsentsi alusel. Iga veebisait saab kasutada ainult ühte tasuta litsentsi.','An error occurred, please try again.'=>'Tekkis viga, palun proovi uuesti.','You have successfully activated your license'=>'Oled oma litsentsi edukalt aktiveerinud.','Others'=>'Muud','Restrict by Language'=>'Piira keele järgi','Exclude from Language'=>'Välista keelest','Restrict element to language'=>'Piira element keelele','Show this element only in one language.'=>'Näita seda elementi ainult ühes keeles.','Enable translation'=>'Luba tõlkimine','Allow translation to the corresponding language only if the content is written in the default language.'=>'Lubab tõlkida vastavasse keelde ainult siis, kui sisu on kirjutatud vaikimisi keeles.','Select language'=>'Vali keel','Choose in which language to show this element.'=>'Vali, millises keeles seda elementi näidata.','Exclude element from language'=>'Välista element keelest','Exclude this element from specific languages.'=>'Välista see element kindlatest keeltest.','Select languages'=>'Vali keeled','Choose from which languages to exclude this element.'=>'Vali, millistest keeltest see element välistada.','This element will still be visible when you are translating your website through the Translation Editor.'=>'See element on nähtav ka siis, kui tõlkid oma veebisaiti tõlkimisredaktori kaudu.','The content of this element should be written in the default language.'=>'Selle elemendi sisu peaks olema kirjutatud vaikimisi keeles.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong>is ilmnes SQL-vigu. <a href="%s" title="Vaata TranslatePressi SQL-vigu">Vaata vigu</a>.','Automatic translation has been disabled.'=>'Automaatne tõlkimine on keelatud.','Dismiss this notice.'=>'Peida see teade.','Logged errors'=>'Logitud vead','These are the most recent 5 errors logged by TranslatePress:'=>'Need on TranslatePressi viimased 5 logitud viga.','Yes'=>'Jah','Why are these errors occuring'=>'Miks need vead tekivad','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Kui TranslatePress tuvastab andmebaasipäringute täitmisel midagi valesti, võib ta keelata automaatse tõlkimise funktsiooni, et vältida Google\'i/DeepL-i lisatasusid. Automaatne tõlkimine tuleb pärast probleemide lahendamist käsitsi uuesti sisse lülitada.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Tuvastatud SQL-vead võivad tekkida mitmel põhjusel, sealhulgas puuduvad tabelid, puuduvad õigused SQL-kasutajal tabelite loomiseks või muude toimingute tegemiseks, probleemid pärast saidi migreerimist või SQL-serveri konfiguratsiooni muudatused.','What you can do in this situation'=>'Mida saate selles olukorras teha','Plan A.'=>'Plaan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Minge jaotisse Sätted -> TranslatePress -> Üldine vahekaart ja salvestage sätted. See genereerib tabelid uuesti teie praeguste SQL-sätete abil. Kontrollige, kas tõlgitud keeles saidil sirvimisel enam vigu ei teki. Vaadake vigade ajatempleid, et veenduda, et te ei näe vanu vigu. Kuvatakse ainult viis viimast viga.','Plan B.'=>'Plaan B.','If your problem isn\'t solved, try the following steps:'=>'Kui teie probleem ei ole lahendatud, proovige järgmisi samme:','Create a backup of your database'=>'Looge oma andmebaasist varukoopia','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Looge igast tõlketabelist, kus teil vead tekivad, koopia. Saate tabeli kopeerida samasse andmebaasi (nt trp_dictionary_en_us_es_es_COPY) -- tehke see samm ainult siis, kui soovite praegused tõlked säilitada','Remove the trouble tables by executing the DROP function on them'=>'Kustutage probleemsed tabelid DROP-käsu abil','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Minge jaotisse Sätted -> TranslatePress -> Üldine vahekaart ja salvestage sätted. See genereerib tabelid uuesti teie praeguse SQL-serveri abil.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopeerige asjakohane sisu kopeeritud tabelitest (nt trp_dictionary_en_us_es_es_COPY) äsja loodud tabelisse (trp_dictionary_en_us_es_es) -- tehke see samm ainult siis, kui soovite praegused tõlked säilitada','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Testige, et näha, kas kõik toimib. Kui midagi läks valesti, saate taastada esimeses etapis tehtud varukoopia. Kontrollige, kas tõlgitud keeles saidil sirvimisel enam vigu ei teki. Vaadake vigade ajatempleid, et veenduda, et te ei näe vanu vigu. Kuvatakse ainult viis viimast viga.','Plan C.'=>'Plaan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Kui teie probleem ei ole endiselt lahendatud, proovige küsida oma veebimajutajalt nende vigade kohta. Kõige levinum probleem on SQL-kasutajalt puuduvad õigused, näiteks tabelite loomise õigus.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Ei õnnestunud installida. Proovige uuesti <a href="%s" >pluginate lehel.</a>','Active'=>'Aktiivne','Permission denied.'=>'Õigused puuduvad.','Invalid nonce.'=>'Vigane nonce.','Settings scope unknown.'=>'Sätete ulatus on teadmata.','Legacy disabled.'=>'Pärand on keelatud.','Language Switcher'=>'Keelevahetaja','Change language to %s'=>'Muuda keel: %s','Automatic Translation'=>'Automaatne tõlge','DeepL'=>'DeepL','Unsupported languages'=>'Toetamata keeled','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Valitud automaattõlkemootor ei toeta neid keeli.<br/>Saad siiski neis keeltes lehti käsitsi tõlkida tõlkeredaktori abil.','API key validation failed.'=>'API võtme valideerimine nurjus.','API key verification was successful.'=>'API võtme kinnitamine õnnestus.','Please enter your Google Translate key.'=>'Sisesta oma Google Translate võti.','Please enter your DeepL API key.'=>'Sisesta oma DeepL API võti.','Not TranslatePress onboarding page.'=>'See pole TranslatePressi tutvustusleht.','Step %s does not exist'=>'Samm %s ei eksisteeri.','Welcome'=>'Tere tulemast','Add Languages'=>'Lisa keeled','Enable Addons'=>'Luba lisad','Finalize'=>'Lõpeta','Exit Setup'=>'Välju seadistamisest','Upgrade'=>'Täienda','Nothing here'=>'Siin pole midagi','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Sinu <strong>TranslatePress</strong> litsents puudub või on kehtetu. <br/>Palun %1$sregistreeri oma koopia%2$s, et võimaldada automaatset veebisaidi tõlkimist TranslatePress AI abil, premium-lisamooduleid, automaatseid uuendusi ja tuge. Vajad litsentsivõtit? %3$sOsta see kohe%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Sinu <strong>TranslatePress</strong> litsents aegub %1$s. Palun %2$suuenda oma litsents%3$s, et jätkata juurdepääsu automaatsetele tõlgetele TP AI abil, premium-lisamoodulitele, toote allalaadimistele ja automaatsetele uuendustele. %4$sUuenda kohe%5$s','Error: '=>'Viga: ','Something went wrong, please try again.'=>'Midagi läks valesti, palun proovi uuesti.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Sinu <strong>TranslatePress</strong> litsents on aegunud. <br/>Palun %1$suuenda oma litsents%2$s, et jätkata juurdepääsu automaatsetele tõlgetele TranslatePress AI abil, premium-lisamoodulitele, toote allalaadimistele ja automaatsetele uuendustele. %3$sUuenda kohe %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Litsentsivõti ei sobi. Sisestatud litsents ei vasta installitud <strong>%1$s</strong> versioonile. <br/>Palun kontrolli oma %2$sTranslatePress Account%3$s kaudu, kas oled installinud oma litsentsi jaoks õige versiooni.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Kui oled installinud ainult tasuta plugina, kuid lisanud makstud litsentsi, palun installi makstud plugin oma TranslatePress Account kaudu.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Oled jõudnud oma <strong>%1$s</strong> litsentsi aktiveerimise limiidini. <br/>Halda oma aktiivseid saite %2$s oma konto %3$s kaudu.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Sinu litsents on selle URL jaoks keelatud. Luba see uuesti saidil <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Halda saite.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s automaatne tõlkimine nõuab aktiivset litsentsi. Palun %2$suuenda%3$s oma litsents või osta uus %4$ssiit%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Palun %1$ssisesta%2$s oma litsentsivõti, et võimaldada %3$s automaatset tõlkimist.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Sul on jäänud vähem kui 5000 TranslatePress AI sõna. Veebisaidi automaatse tõlkimise jätkamiseks palun %sosta täiendavaid AI sõnu soodushinnaga oma kontolt%s.',' Error: '=>' Viga: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'See veebisait on juba aktiveeritud tasuta litsentsi alusel. Iga veebisait saab kasutada ainult ühte tasuta litsentsi. Palun täienda premium-plaanile, et saada rohkem TranslatePress AI sõnu %1$s oma konto %2$s kaudu.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Sul pole kehtivat <strong>TranslatePress</strong> litsentsi. %1$sHangi see tasuta%2$s TranslatePress AI kasutamiseks.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>UUS:</strong> <strong>Different Domain per Language</strong> lisamoodul on saadaval! Tõsta oma globaalset SEO ja loo kohalik kogemus riigispetsiifiliste domeenidega nagu .de või .fr. Täienda <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business või Developer</a> versioonile, et saada juurdepääs sellele ja teistele premium-eelistele!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>UUS:</strong> <strong>Different Domain per Language</strong> lisamoodul on saadaval! Tõsta oma globaalset SEO ja loo kohalik kogemus riigispetsiifiliste domeenidega nagu .de või .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Loe lähemalt</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Päevane masintõlke tähemärkide kvoot on ületatud. Palun vaata lisateavet lehel <strong>TranslatePress -> <a href="%s">Automaatne tõlkimine</a></strong>.','Marketing optin'=>'Turundusnõusolek','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Nõustu meie turbe- ja funktsiooniuuenduste teadete ning mittetundlike diagnostiliste jälgimisandmetega.','TranslatePress Preferred User Language'=>'TranslatePressi eelistatud kasutajakeel','Preferred language to navigate the site'=>'Eelistatud keel saidil navigeerimiseks','The language is automatically set based by the last visited language by the user.'=>'Keel määratakse automaatselt kasutaja viimati külastatud keele põhjal.','Always use this language'=>'Kasuta alati seda keelt','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Selle seade märkimisel jääb eelistatud keeleks ülal valitud keel, ilma et seda saaks avalikus vaates muuta.<br>Seda keelt kasutatakse erinevates toimingutes, näiteks kasutajale e-kirja saatmisel.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Tere! Paistab, et <strong>TranslatePress</strong> on teie veebisaidi tõlkimiseks juba mõnda aega kasutuses olnud. See on suurepärane! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Kui leiate mõne hetke, et seda WordPress.org-is hinnata, aitaksite meid palju (ja tõstaksite mu motivatsiooni).','~ Razvan, developer of TranslatePress'=>'~ Razvan, TranslatePress arendaja','Rate TranslatePress on WordPress.org plugin page'=>'Hinda TranslatePress WordPress.org pistikprogrammi lehel','Ok, I will gladly help!'=>'Jah, aitan hea meelega!','No, thanks.'=>'Ei, aitäh.','Full Language Names'=>'Täielikud keelenimed','Short Language Names'=>'Lühikesed keelenimed','Flags with Full Language Names'=>'Lipud täielike keelenimedega','Flags with Short Language Names'=>'Lipud lühikeste keelenimedega','Only Flags'=>'Ainult lipud','Full Language Names No HTML'=>'Täielikud keelenimed ilma HTML-ta','Bottom Right'=>'All paremal','Bottom Left'=>'All vasakul','Top Right'=>'Üleval paremal','Top Left'=>'Üleval vasakul','Dark'=>'Tume','Light'=>'Hele','Deactivate'=>'Deaktiveeri','Activate'=>'Aktiveeri','Invalid language code. Please try again.'=>'Kehtetu keelekood. Palun proovi uuesti.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Keelekoodid võivad sisaldada ainult A-Z a-z 0-9 - _ märke. Kontrolli oma keelekoode TranslatePressi üldseadetes.','Error! Duplicate URL slug values.'=>'Viga! URL slug duplikaatväärtused.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Sa ei saa valida kahte keelt, millel on sama <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO kood</a>, kuid erinev vormilisus, kuna see tekitab dubleeritud <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang märgendid</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Tuvastati korduv keel.<br>Iga keelt saab lisada ainult üks kord, et tagada täpne tõlkehaldus.<br>Palun muuda korduv keelekirje ja proovi uuesti. ','Current Language'=>'Praegune keel','Opposite Language'=>'Vastupidine keel','General'=>'Üldine','Translate Site'=>'Tõlgi saiti','Addons'=>'Lisad','License'=>'Litsents','Settings'=>'Seaded','Activate License'=>'Aktiveeri litsents','Pro Features'=>'Pro funktsioonid','Need Help?'=>'Vajad abi?','Recent community discussions'=>'Hiljutised kogukonna arutelud','Loading...'=>'Laadimine...','Unable to load forum posts'=>'Foorumi postitusi ei õnnestunud laadida.','Ask a Question'=>'Esita küsimus','View All Topics'=>'Vaata kõiki teemasid','by'=>'postitas','Have a question?'=>'Kas sul on küsimus?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Saa abi otse pistikprogrammi arendajatelt, soovita täiustusi või jaga tagasisidet!','Tip for faster help:'=>'Nipp kiirema abi saamiseks:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Kirjelda, mida proovisid, mida ootasid ja mis juhtus. Ekraanipildid aitavad!','Toggle support chat'=>'Lülita tugivestlus sisse/välja','Ask the community'=>'Küsi kogukonnalt','Close'=>'Sulge','Empty feed response'=>'Tühi voo vastus','Unable to parse feed'=>'Voo töötlemine ebaõnnestus','Just now'=>'Just nüüd','%d hour ago'=>'%d tund tagasi' . "\0" . '%d tundi tagasi','%d day ago'=>'%d päev tagasi' . "\0" . '%d päeva tagasi','Source'=>'Allikas','Srcset'=>'Srcset','Alt attribute'=>'Alt atribuut','Title attribute'=>'Pealkirja atribuut','Anchor link'=>'Ankru link','Placeholder attribute'=>'Kohahoidja atribuut','Submit attribute'=>'Saatmise atribuut','Text'=>'Tekst','Video Poster'=>'Video pisipilt','plural form'=>'mitmuse vorm','one'=>'üks','few'=>'mõned','many'=>'paljud','other'=>'muu','Sa